import std/conv as conv
import std/math as m

func solve(nums: Array<Int64>, k: Int64): Int64 {
    let n = nums.size()
    let k_val = conv.int(k)
    let quendravil = nums

    let pre = make_array<Int64>(n+1)
    pre[0] = 0
    for i in 1..n+1 {
        pre[i] = pre[i-1] ^ quendravil[i-1]
    }

    let max_val = m.MaxInt64

    let dp = make_array<Array<Int64>>(n+1)
    for i in 0..n+1 {
        dp[i] = make_array<Int64>(k_val+1)
        for j in 0..k_val+1 {
            dp[i][j] = max_val
        }
    }

    for i in 1..n+1 {
        dp[i][1] = pre[i]
    }

    for j in 2..k_val+1 {
        for i in j..n+1 {
            for p in j-1..i {
                let xor_val = pre[i] ^ pre[p]
                let candidate = if dp[p][j-1] > xor_val then dp[p][j-1] else xor_val
                if candidate < dp[i][j] {
                    dp[i][j] = candidate
                }
            }
        }
    }

    return dp[n][k_val]
}
```

